final_source:
build for javascript backend

when user sends calc to /api/calculate:
  op = calc's operation
  a_val = calc's a
  b_val = calc's b

  is_divide = op is 'divide'
  is_zero = b_val is 0
  if is_divide and is_zero:
    send back 'Division by zero' with status 400

  result is 0
  if op is 'add':
    result is a_val + b_val
  if op is 'subtract':
    result is a_val - b_val
  if op is 'multiply':
    result is a_val * b_val
  if op is 'divide':
    result is a_val / b_val

  send back result as { result }
